import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.next();

        // Vulnerability: Improperly handling user input without validating the length
        char[] buffer = new char[10]; // Fixed size buffer

        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("User input copied into buffer: " + new String(buffer));
    }
}

